    char p[] = "It is 8";
    char result[20];
    for (int i = 0; p[i] != '\0'; i++) {
        if (isupper(p[i]))
            result[i] = (p[i] - 'A' + 5) % 26 + 'A';
        else if (islower(p[i]))
            result[i] = (p[i] - 'a' + 10) % 26 + 'a';
        else if (isdigit(p[i]))
            result[i] = (p[i] - '0' + 3) % 10 + '0';
        else
            result[i] = p[i];
    }
    result[7] = '\0';
    printf("%s", result);
    return 0;
}

#include <stdio.h>
#include <string.h>
void fn(char* str) {
    int len = strlen(str);
    int left = 0, right = len - 1;
    while (left < right) {
        char tmp = str[left];
        str[left] = str[right];
        str[right] = tmp;
        left++; right--;
    }
}
int main() {
    char str[100] = "ABCDEFGH";
    fn(str);
    int len = strlen(str);
    for (int i = 1; i < len; i += 2)
        printf("%c", str[i]);
    return 0;
}

#include <stdio.h>
void fn(char *d, const char *s) {
    while (*s) {
        *d = *s;
        d++;
        s++;
    }
    *d = '\0';
}
int main() {
    const char* str1 = "first";
    char str2[50] = "teststring";
    fn(str2, str1);
    int result = 0;
    for (int i = 0; str2[i] != '\0'; i++) {
        result += i;
    }
    printf("%d", result);
    return 0;
}

